            paramList.push_back(params.substr(start, end - start));
            start = end + 1;
        }
        paramList.push_back(params.substr(start));

        std::sort(paramList.begin(), paramList.end());

        result = base + "?";
        for (size_t i = 0; i < paramList.size(); ++i) {
